import{_ as a,o,c as l,ag as i}from"./chunks/framework.D2Ob5GRY.js";const m=JSON.parse('{"title":"LLM 服务商配置详解","description":"","frontmatter":{},"headers":[],"relativePath":"deployment/llm-providers.md","filePath":"deployment/llm-providers.md"}'),r={name:"deployment/llm-providers.md"};function t(n,e,s,d,p,h){return o(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="llm-服务商配置详解" tabindex="-1">LLM 服务商配置详解 <a class="header-anchor" href="#llm-服务商配置详解" aria-label="Permalink to &quot;LLM 服务商配置详解&quot;">​</a></h1><blockquote><p>通过界面或 api_keys.json 配置各 Provider；含 DeepSeek、DashScope、OpenAI、Gemini 与代理说明。</p></blockquote><h2 id="配置入口-通过界面-vs-直接编辑-api-keys-json" tabindex="-1">配置入口：通过界面 vs 直接编辑 api_keys.json <a class="header-anchor" href="#配置入口-通过界面-vs-直接编辑-api-keys-json" aria-label="Permalink to &quot;配置入口：通过界面 vs 直接编辑 api_keys.json&quot;">​</a></h2><ul><li><strong>推荐</strong>：系统设置 → LLM 与文献配置，填写各 API Key 后保存，写入 <code>CONFIG_DIR/api_keys.json</code>，优先于 .env。</li><li><strong>进阶</strong>：直接编辑 <code>CONFIG_DIR/api_keys.json</code>（需与界面格式一致），或通过 .env 配置对应 <code>*_API_KEY</code>。</li></ul><h2 id="deepseek-配置-推荐-国内直连" tabindex="-1">DeepSeek 配置（推荐，国内直连） <a class="header-anchor" href="#deepseek-配置-推荐-国内直连" aria-label="Permalink to &quot;DeepSeek 配置（推荐，国内直连）&quot;">​</a></h2><ol><li>打开 <a href="https://platform.deepseek.com/" target="_blank" rel="noreferrer">DeepSeek 开放平台</a> 创建 API Key。</li><li>在系统设置中填写「DeepSeek API Key」并保存。</li><li>可选：在智能体配置页为各智能体选择 DeepSeek 模型（如 deepseek-chat、deepseek-reasoner）。</li></ol><h2 id="阿里云-dashscope-通义千问-配置" tabindex="-1">阿里云 DashScope / 通义千问 配置 <a class="header-anchor" href="#阿里云-dashscope-通义千问-配置" aria-label="Permalink to &quot;阿里云 DashScope / 通义千问 配置&quot;">​</a></h2><ol><li>登录阿里云控制台，开通 DashScope 服务，创建 API Key。</li><li>在系统设置中填写「通义千问 (Qwen) API Key」并保存。</li><li>模型可选 qwen-turbo、qwen-plus、qwen-max 等。</li></ol><h2 id="openai-配置-需代理" tabindex="-1">OpenAI 配置（需代理） <a class="header-anchor" href="#openai-配置-需代理" aria-label="Permalink to &quot;OpenAI 配置（需代理）&quot;">​</a></h2><ol><li>在 OpenAI 平台创建 API Key。</li><li>填写「ChatGPT / OpenAI API Key」。</li><li>若在国内，需在「代理配置」中填写 HTTP/HTTPS 代理，使请求能访问 api.openai.com。</li></ol><h2 id="google-gemini-配置-需代理" tabindex="-1">Google Gemini 配置（需代理） <a class="header-anchor" href="#google-gemini-配置-需代理" aria-label="Permalink to &quot;Google Gemini 配置（需代理）&quot;">​</a></h2><ol><li>在 Google AI Studio 或 Cloud 创建 API Key。</li><li>填写「Gemini API Key」。</li><li>国内需配置代理访问。</li></ol><h2 id="代理配置说明-http-代理-socks5" tabindex="-1">代理配置说明（HTTP 代理 / SOCKS5） <a class="header-anchor" href="#代理配置说明-http-代理-socks5" aria-label="Permalink to &quot;代理配置说明（HTTP 代理 / SOCKS5）&quot;">​</a></h2><p>在系统设置「代理配置」中填写 <code>PROXY_URL</code> 或 <code>HTTPS_PROXY</code>（如 <code>http://127.0.0.1:7890</code>）。部分环境支持 SOCKS5，具体以后端实现为准。</p><h2 id="多-provider-配置与自动降级说明" tabindex="-1">多 Provider 配置与自动降级说明 <a class="header-anchor" href="#多-provider-配置与自动降级说明" aria-label="Permalink to &quot;多 Provider 配置与自动降级说明&quot;">​</a></h2><p>配置多个 Provider 后，系统会按「智能体配置」或默认档位选择优先使用的模型；若当前 Provider 不可用（如 429、超时），会自动降级到其他已配置的 Provider。</p><h2 id="api-key-使用量估算参考" tabindex="-1">API Key 使用量估算参考 <a class="header-anchor" href="#api-key-使用量估算参考" aria-label="Permalink to &quot;API Key 使用量估算参考&quot;">​</a></h2><p>（占位：可根据各厂商定价与典型请求 token 数给出粗略估算。）</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/deployment/proxy-config.html">网络与代理配置</a></li><li><a href="/docs/reference/llm-reference.html">LLM Provider 参数参考</a></li></ul>',20)])])}const P=a(r,[["render",t]]);export{m as __pageData,P as default};
